package com.fasterxml.jackson.databind.ser;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "com.fasterxml.jackson.databind.ser.steps",
    plugin = {"pretty", "html:target/cucumber-reports.html"}
)
public class CucumberTest {
}

package com.fasterxml.jackson.databind.ser.steps;

import com.fasterxml.jackson.annotation.JsonFormat;
import com.fasterxml.jackson.annotation.JsonPropertyOrder;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.SerializationFeature;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.junit.Assert;

public class StepDefs {

    @JsonPropertyOrder({ "x", "y" })
    @JsonFormat(shape = JsonFormat.Shape.ARRAY)
    public static class ArrayPOJO {
        public String x;
        public String y;

        public ArrayPOJO(String x, String y) {
            this.x = x;
            this.y = y;
        }
    }

    private ObjectMapper mapper = new ObjectMapper();
    private ArrayPOJO pojo;
    private String jsonOutput;

    @Given("a POJO class configured to use JSON Array format")
    public void a_POJO_class_configured_to_use_JSON_Array_format() {
        // Defined above
    }

    @Given("the POJO has a field with a null value")
    public void the_POJO_has_a_field_with_a_null_value() {
        pojo = new ArrayPOJO("notNull", null);
    }

    @When("the POJO is serialized to JSON")
    public void the_POJO_is_serialized_to_JSON() {
        try {
            jsonOutput = mapper.writeValueAsString(pojo);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @Then("the resulting JSON array should contain a {string} value for the field")
    public void the_resulting_JSON_array_should_contain_a_value_for_the_field(String expectedValue) {
        // expectedValue is "null" (string literal in feature, but logically null in JSON)
        // jsonOutput should be ["notNull",null]
        Assert.assertTrue("JSON output should contain null", jsonOutput.contains("null"));
    }

    @Then("the {string} value should appear exactly once for that field position")
    public void the_value_should_appear_exactly_once_for_that_field_position(String expectedValue) {
        // Check for double nulls like ["notNull",null,null] or ["notNull",nullnull]
        // The bug description says "double writing of null". 

        // Simple check: count occurrences of "null"
        int count = 0;
        int idx = 0;
        while ((idx = jsonOutput.indexOf("null", idx)) != -1) {
            count++;
            idx += 4;
        }

        // Note: this simple counting assumes "x" doesn't contain "null" string.
        // In our case x is "notNull", so it's safe.
        Assert.assertEquals("Should appear exactly once", 1, count);

        // Also verify structure roughly
        Assert.assertEquals("[\"notNull\",null]", jsonOutput);
    }
}
